contracts/MediPearsToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

contract MediPearsToken is ERC20, AccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant CONTROLLER_ROLE = keccak256("CONTROLLER_ROLE");

    constructor(address admin) ERC20("MediPears", "MPRS") {
        require(admin != address(0), "admin is zero address");

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ADMIN_ROLE, admin);
    }

    function decimals() public pure override returns (uint8) {
        return 18;
    }

    function setRewardsController(address controller) external onlyRole(ADMIN_ROLE) {
        require(controller != address(0), "controller is zero address");
        _grantRole(CONTROLLER_ROLE, controller);
    }

    function revokeRewardsController(address controller) external onlyRole(ADMIN_ROLE) {
        _revokeRole(CONTROLLER_ROLE, controller);
    }

    function adminMint(address to, uint256 amount) external onlyRole(ADMIN_ROLE) {
        _mint(to, amount);
    }

    function mintReward(address to, uint256 amount) external onlyRole(CONTROLLER_ROLE) {
        _mint(to, amount);
    }
}

contracts/RewardsController.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./MediPearsToken.sol";

contract RewardsController is AccessControl, Pausable {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant ORACLE_ROLE = keccak256("ORACLE_ROLE");

    MediPearsToken public immutable token;

    mapping(bytes32 => bool) public eventIdUsed;
    mapping(address => uint256) public totalRewardsByUser;

    uint256 public maxRewardPerEvent;
    uint256 public maxRewardsPerUser;

    event RewardIssued(address indexed user, uint256 amount, bytes32 indexed eventId);
    event RewardCapsUpdated(uint256 maxRewardPerEvent, uint256 maxRewardsPerUser);

    constructor(
        address tokenAddress,
        address admin,
        address oracle,
        uint256 initialMaxRewardPerEvent,
        uint256 initialMaxRewardsPerUser
    ) {
        require(tokenAddress != address(0), "token is zero address");
        require(admin != address(0), "admin is zero address");
        require(oracle != address(0), "oracle is zero address");
        require(initialMaxRewardPerEvent > 0, "invalid event cap");
        require(initialMaxRewardsPerUser > 0, "invalid user cap");

        token = MediPearsToken(tokenAddress);
        maxRewardPerEvent = initialMaxRewardPerEvent;
        maxRewardsPerUser = initialMaxRewardsPerUser;

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ADMIN_ROLE, admin);
        _grantRole(ORACLE_ROLE, oracle);
    }

    function issueReward(address user, uint256 amount, bytes32 eventId)
        external
        onlyRole(ORACLE_ROLE)
        whenNotPaused
    {
        require(user != address(0), "user is zero address");
        require(amount > 0, "amount is zero");
        require(!eventIdUsed[eventId], "event already rewarded");
        require(amount <= maxRewardPerEvent, "amount above event cap");

        uint256 nextTotal = totalRewardsByUser[user] + amount;
        require(nextTotal <= maxRewardsPerUser, "amount above user cap");

        eventIdUsed[eventId] = true;
        totalRewardsByUser[user] = nextTotal;

        token.mintReward(user, amount);

        emit RewardIssued(user, amount, eventId);
    }

    function setRewardCaps(uint256 newMaxRewardPerEvent, uint256 newMaxRewardsPerUser)
        external
        onlyRole(ADMIN_ROLE)
    {
        require(newMaxRewardPerEvent > 0, "invalid event cap");
        require(newMaxRewardsPerUser > 0, "invalid user cap");

        maxRewardPerEvent = newMaxRewardPerEvent;
        maxRewardsPerUser = newMaxRewardsPerUser;

        emit RewardCapsUpdated(newMaxRewardPerEvent, newMaxRewardsPerUser);
    }

    function pause() external onlyRole(ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(ADMIN_ROLE) {
        _unpause();
    }
}

contracts/RewardsVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./MediPearsToken.sol";

contract RewardsVault is AccessControl {
    using SafeERC20 for IERC20;

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    uint256 public constant MIN_LOCK_PERIOD = 7 days;

    uint256 public constant BRONZE_THRESHOLD = 100 ether;
    uint256 public constant SILVER_THRESHOLD = 500 ether;
    uint256 public constant GOLD_THRESHOLD = 2000 ether;
    uint256 public constant DIAMOND_THRESHOLD = 5000 ether;

    uint256 public constant BRONZE_BOOST_BPS = 500;
    uint256 public constant SILVER_BOOST_BPS = 1500;
    uint256 public constant GOLD_BOOST_BPS = 3000;
    uint256 public constant DIAMOND_BOOST_BPS = 5000;

    enum Tier {
        None,
        Bronze,
        Silver,
        Gold,
        Diamond
    }

    MediPearsToken public immutable token;

    mapping(address => uint256) public stakedBalance;
    mapping(address => uint256) public unlockTimestamp;
    mapping(address => Tier) public userTier;

    event Staked(address indexed user, uint256 amount, uint256 unlockTimestamp, Tier tier);
    event Unstaked(address indexed user, uint256 amount, Tier tier);

    constructor(address tokenAddress, address admin) {
        require(tokenAddress != address(0), "token is zero address");
        require(admin != address(0), "admin is zero address");

        token = MediPearsToken(tokenAddress);

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ADMIN_ROLE, admin);
    }

    function stake(uint256 amount) external {
        require(amount > 0, "amount is zero");

        stakedBalance[msg.sender] += amount;
        unlockTimestamp[msg.sender] = block.timestamp + MIN_LOCK_PERIOD;

        userTier[msg.sender] = _tierForAmount(stakedBalance[msg.sender]);

        IERC20(address(token)).safeTransferFrom(msg.sender, address(this), amount);

        emit Staked(msg.sender, amount, unlockTimestamp[msg.sender], userTier[msg.sender]);
    }

    function unstake(uint256 amount) external {
        require(amount > 0, "amount is zero");
        require(block.timestamp >= unlockTimestamp[msg.sender], "stake is still locked");
        require(stakedBalance[msg.sender] >= amount, "insufficient staked balance");

        stakedBalance[msg.sender] -= amount;
        userTier[msg.sender] = _tierForAmount(stakedBalance[msg.sender]);

        IERC20(address(token)).safeTransfer(msg.sender, amount);

        emit Unstaked(msg.sender, amount, userTier[msg.sender]);
    }

    function getBoostBps(address user) external view returns (uint256) {
        Tier tier = userTier[user];
        if (tier == Tier.Diamond) return DIAMOND_BOOST_BPS;
        if (tier == Tier.Gold) return GOLD_BOOST_BPS;
        if (tier == Tier.Silver) return SILVER_BOOST_BPS;
        if (tier == Tier.Bronze) return BRONZE_BOOST_BPS;
        return 0;
    }

    function _tierForAmount(uint256 amount) internal pure returns (Tier) {
        if (amount >= DIAMOND_THRESHOLD) return Tier.Diamond;
        if (amount >= GOLD_THRESHOLD) return Tier.Gold;
        if (amount >= SILVER_THRESHOLD) return Tier.Silver;
        if (amount >= BRONZE_THRESHOLD) return Tier.Bronze;
        return Tier.None;
    }
}

